import numpy as np
from geosat.cloud import rasterization
from geosat.cloud.bounding_image import BoundingImage  # type: ignore[attr-defined]
from geosat.cloud.projection_image import ProjectionImage  # type: ignore[attr-defined]

import psanp.segmentation.ground.lane_mark.morphological_segmentation as ms


def extract_segmentation(cloud, input_code, k=0.05, partial=None):
    intensity_image = rasterization.max_normalized_intensity_raster(
        cloud, k, mask=cloud.classification == input_code
    )
    intensity_mask = (
        (np.nan_to_num(intensity_image) * (255 * partial)).clip(max=255)
        if partial is not None
        else ms.extract_high_intensity_mask(intensity_image, gsd=k)
    )
    bounding_image = BoundingImage(
        cloud.bb_min(), cloud.bb_max(), k, axis_width=1, axis_height=0
    )
    return ProjectionImage(bounding_image, intensity_mask)
